// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Staking {
    // -----------------------------
    // STORAGE
    // -----------------------------

    // Amount of ETH each user has staked
    mapping(address => uint256) public balances;

    // Last time rewards were calculated for each user
    mapping(address => uint256) public lastUpdate;

    // 10% Annual Percentage Rate
    uint256 public constant APR = 10;
    uint256 public constant SECONDS_IN_YEAR = 365 days;

    // -----------------------------
    // EVENTS (professional touch)
    // -----------------------------
    event Staked(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);
    event RewardsClaimed(address indexed user, uint256 reward);

    // -----------------------------
    // INTERNAL REWARD CALCULATION
    // -----------------------------
    function calculateRewards(address user) public view returns (uint256) {
        if (balances[user] == 0) {
            return 0;
        }

        uint256 timeStaked = block.timestamp - lastUpdate[user];

        uint256 reward = (balances[user] * APR * timeStaked)
            / (100 * SECONDS_IN_YEAR);

        return reward;
    }

    // -----------------------------
    // STAKE ETH
    // -----------------------------
    function stake() external payable {
        require(msg.value > 0, "Cannot stake 0 ETH");

        // Add pending rewards before increasing stake
        if (balances[msg.sender] > 0) {
            uint256 reward = calculateRewards(msg.sender);
            balances[msg.sender] += reward;
        }

        balances[msg.sender] += msg.value;
        lastUpdate[msg.sender] = block.timestamp;

        emit Staked(msg.sender, msg.value);
    }

    // -----------------------------
    // WITHDRAW STAKED ETH
    // -----------------------------
    function withdraw(uint256 amount) external {
        require(amount > 0, "Cannot withdraw 0");
        require(balances[msg.sender] >= amount, "Insufficient balance");

        uint256 reward = calculateRewards(msg.sender);

        balances[msg.sender] = balances[msg.sender] + reward - amount;
        lastUpdate[msg.sender] = block.timestamp;

        payable(msg.sender).transfer(amount);

        emit Withdrawn(msg.sender, amount);
    }

    // -----------------------------
    // CLAIM ONLY REWARDS
    // -----------------------------
    function claimRewards() external {
        uint256 reward = calculateRewards(msg.sender);
        require(reward > 0, "No rewards available");

        lastUpdate[msg.sender] = block.timestamp;
        payable(msg.sender).transfer(reward);

        emit RewardsClaimed(msg.sender, reward);
    }

    // -----------------------------
    // VIEW HELPERS
    // -----------------------------
    function getBalance(address user) external view returns (uint256) {
        return balances[user];
    }

    function getPendingRewards(address user) external view returns (uint256) {
        return calculateRewards(user);
    }
}

